import { useEffect } from "react";
import "./BookingModal.css";

export default function BookingModal({
  isOpen,
  onClose,
  formData,
  onChange,
  onSubmit,
}) {
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (event) => {
      if (event.key === "Escape") {
        onClose();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="booking-modal" role="dialog" aria-modal="true">
      <div className="booking-modal__backdrop" onClick={onClose} />
      <div className="booking-modal__panel">
        <button
          type="button"
          className="booking-modal__close"
          onClick={onClose}
          aria-label="Close booking form"
        >
          ×
        </button>

        <div className="booking-modal__header">
          <p className="label">Book a Session</p>
          <h2>Reserve your date</h2>
          <p>Leave your mobile number and choose a date to book a session.</p>
        </div>

        <form className="booking-modal__form" onSubmit={onSubmit}>
          <label className="booking-modal__label">
            Mobile number
            <input
              type="tel"
              name="phone"
              value={formData.phone}
              onChange={onChange}
              placeholder="Enter mobile number"
              className="booking-modal__input"
              pattern="[0-9]{10,15}"
              required
            />
          </label>

          <label className="booking-modal__label">
            Booking date
            <input
              type="date"
              name="date"
              value={formData.date}
              onChange={onChange}
              className="booking-modal__input"
              required
            />
          </label>

          <button type="submit" className="booking-modal__submit">
            Send request
          </button>
        </form>
      </div>
    </div>
  );
}
